import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [availableDays, setAvailableDays] = useState([]);
  const [availableTimes, setAvailableTimes] = useState([]);

  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  const [feedbacks, setFeedbacks] = useState([]);
  const [rating, setRating] = useState("");
  const [comment, setComment] = useState("");

  const [popup, setPopup] = useState({ show: false, message: "" });

  // ================= GET DOCTOR =================
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setDoctor(data.doctor);
        setAvailableDays(data.doctor.available_days || []);
        setAvailableTimes(data.doctor.available_time_slots || []);
      });
  }, [doctor_id]);

  // ================= GET FEEDBACK =================
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => setFeedbacks(data));
  }, [doctor_id]);

  const avgRating =
    feedbacks.length > 0
      ? (
          feedbacks.reduce((a, b) => a + b.rating, 0) / feedbacks.length
        ).toFixed(1)
      : 0;

  // ================= DATE CHECK =================
  const getDayName = (dateStr) =>
    new Date(dateStr).toLocaleDateString("en-US", {
      weekday: "long",
    });

  const handleDateChange = (e) => {
    const selectedDate = e.target.value;
    const dayName = getDayName(selectedDate);

    if (!availableDays.includes(dayName)) {
      setPopup({
        show: true,
        message: `Doctor not available on ${dayName}`,
      });
      setDate("");
      return;
    }

    setDate(selectedDate);
  };

  // ================= BOOK FLOW =================
  const handleBook = () => {
    if (!date || !time) {
      setPopup({
        show: true,
        message: "Please select date and time",
      });
      return;
    }

    navigate("/appointment", {
      state: {
        doctor,
        doctor_id,
        date,
        time,
      },
    });
  };

  // ================= FEEDBACK =================
  const handleSubmitFeedback = () => {
    if (!rating || !comment) {
      setPopup({ show: true, message: "Fill rating and comment" });
      return;
    }

    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
      body: JSON.stringify({ rating, comment }),
    })
      .then((res) => res.json())
      .then((data) => {
        setFeedbacks([data, ...feedbacks]);
        setRating("");
        setComment("");
      });
  };

  if (!doctor) return <h2 style={styles.loading}>Loading...</h2>;

  return (
    <div style={styles.container}>
      <Navbar />

      {/* ================= POPUP ================= */}
      {popup.show && (
        <div style={styles.overlay}>
          <div style={styles.popupCard}>
            <p>{popup.message}</p>
            <button onClick={() => setPopup({ show: false })}>OK</button>
          </div>
        </div>
      )}

      <div style={styles.wrapper}>
        {/* ================= DOCTOR CARD ================= */}
        <div style={styles.card}>

          <img
            src={
              doctor.image ||
              "https://cdn-icons-png.flaticon.com/512/387/387561.png"
            }
            alt={doctor.name}
            style={styles.image}
          />

          <div style={styles.info}>
            <h2>{doctor.name}</h2>

            <p>👨‍⚕️ {doctor.field}</p>
            <p>🎓 {doctor.qualification}</p>
            <p>⏳ {doctor.experience} years</p>
            <p>⭐ Rating: {avgRating}</p>
            <p>⚧ Gender: {doctor.gender || "Not Available"}</p>

            {/* BOOKING */}
            <div style={styles.booking}>
              <input type="date" value={date} onChange={handleDateChange} />

              <select value={time} onChange={(e) => setTime(e.target.value)}>
                <option value="">Select Time</option>
                {availableTimes.map((t, i) => (
                  <option key={i}>{t}</option>
                ))}
              </select>

              <button onClick={handleBook}>Book Appointment</button>
            </div>
          </div>
        </div>

        {/* ================= FEEDBACK ================= */}
        <div style={styles.feedbackBox}>
          <h3>Patient Reviews</h3>

          <select value={rating} onChange={(e) => setRating(e.target.value)}>
            <option value="">Rating</option>
            <option value="5">⭐⭐⭐⭐⭐</option>
            <option value="4">⭐⭐⭐⭐</option>
            <option value="3">⭐⭐⭐</option>
            <option value="2">⭐⭐</option>
            <option value="1">⭐</option>
          </select>

          <textarea
            placeholder="Write comment..."
            value={comment}
            onChange={(e) => setComment(e.target.value)}
          />

          <button onClick={handleSubmitFeedback}>Submit</button>

          <div style={styles.reviewList}>
            {feedbacks.map((f, i) => (
              <div key={i} style={styles.reviewCard}>
                <b>{f.user_name}</b>
                <p>{"⭐".repeat(f.rating)}</p>
                <p>{f.comment}</p>
              </div>
            ))}
          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Doctorprofile;

/* ================= STYLES ================= */
const styles = {
  container: { background: "#f4f6f9", minHeight: "100vh" },

  wrapper: {
    display: "flex",
    gap: "20px",
    padding: "30px",
    justifyContent: "center",
  },

  card: {
    background: "#fff",
    padding: "20px",
    borderRadius: "12px",
    display: "flex",
    gap: "20px",
    width: "60%",
    boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
  },

  image: {
    width: "150px",
    height: "150px",
    borderRadius: "50%",
  },

  info: { flex: 1 },

  booking: {
    marginTop: "10px",
    display: "flex",
    gap: "10px",
  },

  feedbackBox: {
    width: "30%",
    background: "#fff",
    padding: "20px",
    borderRadius: "12px",
  },

  reviewList: {
    marginTop: "15px",
  },

  reviewCard: {
    background: "#f1f1f1",
    padding: "10px",
    marginTop: "10px",
    borderRadius: "8px",
  },

  overlay: {
    position: "fixed",
    top: 0,
    left: 0,
    width: "100%",
    height: "100%",
    background: "rgba(0,0,0,0.5)",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  popupCard: {
    background: "#fff",
    padding: "20px",
    borderRadius: "10px",
  },

  loading: {
    textAlign: "center",
    marginTop: "50px",
  },
};
